import re

def syntactic_verify(answer: str, num_docs: int) -> list[int]:
    """Return any cited indices that are out of range."""
    cited = [int(m) for m in re.findall(r'\[(\d+)\]', answer)]
    return [i for i in cited if i < 1 or i > num_docs]

def semantic_verify_sentence(sentence: str, cited_docs: list[str], nli) -> bool:
    """Return True if any cited doc entails the sentence."""
    for doc_text in cited_docs:
        result = nli(f"{doc_text} [SEP] {sentence}", truncation=True, max_length=512)
        scores = {r["label"].upper(): r["score"] for r in result}
        if scores.get("ENTAILMENT", 0) >= 0.6:
            return True
    return False

# Syntactic check
bad = syntactic_verify(result.answer, len(docs))
if bad:
    print(f"WARNING: out-of-range citations {bad} — answer may be hallucinated")

# Semantic check (optional, higher cost)
sentences = [s.strip() for s in result.answer.split(".") if s.strip()]
for sent in sentences:
    indices = [int(m) for m in re.findall(r'\[(\d+)\]', sent)]
    cited_texts = [docs[i-1].page_content for i in indices if 1 <= i <= len(docs)]
    if cited_texts and not semantic_verify_sentence(sent, cited_texts, nli):
        print(f"Unsupported claim: {sent}")
